mapper.insert:
INSERT INTO J_직원 (아이디, 이름, 이메일, 전화번호, 최초입사일, 현재재직상태, 다우사번, 비고, 등록일, 수정일)
VALUES (#{userId}, #{name}, #{email,jdbcType=NVARCHAR}, #{phone,jdbcType=NVARCHAR}, #{hireDate,jdbcType=DATE}, N'재직',
        NULLIF(#{daouNo,jdbcType=NVARCHAR}, N''), #{note,jdbcType=NVARCHAR}, GETDATE(), GETDATE());

INSERT INTO J_직원_계정 (아이디, 비밀번호, 계정상태)
VALUES (#{userId}, #{password}, N'사용');

INSERT INTO J_직원_재직 (아이디, 주부서코드, 지점명, 직급, 권한, 관리자권한, 최종발령일)
VALUES (#{userId},
        #{deptCode},
        (SELECT 지점명 FROM J_부서 WHERE 부서코드 = #{deptCode}),
        #{position,jdbcType=NVARCHAR},
        ISNULL(#{role}, N'상담'),
        ISNULL(#{isAdmin}, 0),
        #{hireDate,jdbcType=DATE});

INSERT INTO J_직원_부서배치 (직원아이디, 부서코드, 주부서여부, 시작일)
VALUES (#{userId}, #{deptCode}, 1, ISNULL(#{hireDate,jdbcType=DATE}, GETDATE()));


    INSERT INTO J_직원_재직기간 (직원아이디, 재직순번, 입사일)
    VALUES (#{userId}, 1, #{hireDate,jdbcType=DATE});


INSERT INTO J_직원_발령이력 (아이디, 발령유형, 발령일, 신규부서코드, 사유, 등록일시)
VALUES (#{userId}, N'입사', ISNULL(#{hireDate,jdbcType=DATE}, GETDATE()), #{deptCode}, N'HR 신규 등록', GETDATE());

mapper.update:
UPDATE J_직원 SET 이름 = #{name}, 이메일 = #{email,jdbcType=NVARCHAR}, 전화번호 = #{phone,jdbcType=NVARCHAR}, 최초입사일 = #{hireDate,jdbcType=DATE}, 다우사번 = NULLIF(#{daouNo,jdbcType=NVARCHAR}, N''), 비고 = #{note,jdbcType=NVARCHAR}, 수정일 = GETDATE() WHERE 아이디 = #{userId};
UPDATE J_직원_계정 SET 계정상태 = #{accountStatus} WHERE 아이디 = #{userId};
UPDATE J_직원_재직 SET 직급 = #{position,jdbcType=NVARCHAR}, 권한 = ISNULL(#{role}, N'상담'), 관리자권한 = ISNULL(#{isAdmin}, 0), 주부서코드 = #{deptCode}, 지점명 = (SELECT 지점명 FROM J_부서 WHERE 부서코드 = #{deptCode}), 최종발령일 = #{lastAssignDate,jdbcType=DATE}, 수정일 = GETDATE() WHERE 아이디 = #{userId};
UPDATE J_직원_부서배치 SET 부서코드 = #{deptCode} WHERE 직원아이디 = #{userId} AND 종료일 IS NULL AND 주부서여부 = 1;

UPDATE J_직원
SET 현재재직상태 = N'퇴사', 수정일 = GETDATE()
WHERE 아이디 = #{userId};

UPDATE J_직원_재직기간
SET 퇴사일 = CAST(GETDATE() AS date)
WHERE 직원아이디 = #{userId} AND 퇴사일 IS NULL;
